 {"id":"asupersync-0whz","title":"[HTTP] Implement Body Types and Connection Management","description":"# Body Types and Connection Management

## Overview
HTTP body abstraction and connection pooling for efficient HTTP client.

## Implementation

### Body Trait
```rust
pub trait Body {
    type Data: Buf;
    type Error;

    fn poll_frame(
        self: Pin<&mut Self>,
        cx: &mut Context<'_>,
    ) -> Poll<Option<Result<Frame<Self::Data>, Self::Error>>>;

    fn is_end_stream(&self) -> bool { false }
    fn size_hint(&self) -> SizeHint { SizeHint::default() }
}

pub enum Frame<T> {
    Data(T),
    Trailers(HeaderMap),
}

pub struct SizeHint {
    lower: u64,
    upper: Option<u64>,
}
```

### Common Body Types
```rust
// Empty body
pub struct Empty;
impl Body for Empty {
    type Data = Bytes;
    type Error = Infallible;

    fn poll_frame(self: Pin<&mut Self>, _: &mut Context<'_>) -> Poll<Option<Result<Frame<Bytes>, Infallible>>> {
        Poll::Ready(None)
    }

    fn is_end_stream(&self) -> bool { true }
}

// Full body (known size)
pub struct Full<D> {
    data: Option<D>,
}

impl<D: Buf> Body for Full<D> {
    type Data = D;
    type Error = Infallible;

    fn poll_frame(self: Pin<&mut Self>, _: &mut Context<'_>) -> Poll<Option<Result<Frame<D>, Infallible>>> {
        let data = self.get_mut().data.take();
        Poll::Ready(data.map(|d| Ok(Frame::Data(d))))
    }
}

// Streaming body
pub struct StreamBody<S> {
    stream: S,
}

impl<S, D, E> Body for StreamBody<S>
where
    S: Stream<Item = Result<Frame<D>, E>>,
    D: Buf,
{
    type Data = D;
    type Error = E;

    fn poll_frame(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Result<Frame<D>, E>>> {
        Pin::new(&mut self.get_mut().stream).poll_next(cx)
    }
}
```

### Connection Pool
```rust
pub struct ConnectionPool<K, C> {
    connections: Mutex<HashMap<K, Vec<PooledConnection<C>>>>,
    config: PoolConfig,
}

struct PooledConnection<C> {
    conn: C,
    created: Instant,
    last_used: Instant,
    request_count: usize,
}

pub struct PoolConfig {
    max_idle_per_host: usize,
    idle_timeout: Duration,
    max_lifetime: Duration,
}

impl<K: Hash + Eq + Clone, C> ConnectionPool<K, C> {
    pub fn checkout(&self, key: &K) -> Option<C> {
        let mut conns = self.connections.lock().unwrap();
        if let Some(pool) = conns.get_mut(key) {
            while let Some(mut pc) = pool.pop() {
                // Check if connection is still valid
                if pc.created.elapsed() < self.config.max_lifetime
                    && pc.last_used.elapsed() < self.config.idle_timeout
                {
                    pc.last_used = Instant::now();
                    return Some(pc.conn);
                }
                // Drop stale connection
            }
        }
        None
    }

    pub fn checkin(&self, key: K, conn: C) {
        let mut conns = self.connections.lock().unwrap();
        let pool = conns.entry(key).or_insert_with(Vec::new);

        if pool.len() < self.config.max_idle_per_host {
            pool.push(PooledConnection {
                conn,
                created: Instant::now(),
                last_used: Instant::now(),
                request_count: 0,
            });
        }
        // Else drop connection
    }
}
```

### HTTP Client
```rust
pub struct Client {
    pool: ConnectionPool<Authority, HttpConnection>,
    connector: HttpConnector,
    config: ClientConfig,
}

impl Client {
    pub async fn request(&self, req: Request<impl Body>) -> Result<Response<Incoming>, ClientError> {
        let authority = req.uri().authority().cloned()
            .ok_or(ClientError::MissingAuthority)?;

        // Try to reuse pooled connection
        let conn = match self.pool.checkout(&authority) {
            Some(conn) => conn,
            None => self.connector.connect(&authority).await?,
        };

        let (resp, conn) = conn.send_request(req).await?;

        // Return to pool if keep-alive
        if should_keep_alive(&resp) {
            self.pool.checkin(authority, conn);
        }

        Ok(resp)
    }
}
```

