```rust
#[tokio::test]
async fn test_connection_pool_reuse() {
    let pool = ConnectionPool::new(PoolConfig::default());

    // First request creates new connection
    let conn = MockConnection::new();
    pool.checkin("host".to_string(), conn);

    // Second checkout reuses
    let reused = pool.checkout(&"host".to_string());
    assert!(reused.is_some());

    // Pool now empty
    assert!(pool.checkout(&"host".to_string()).is_none());
}

#[tokio::test]
async fn test_body_streaming() {
    let stream = stream::iter(vec![
        Ok(Frame::Data(Bytes::from("chunk1"))),
        Ok(Frame::Data(Bytes::from("chunk2"))),
    ]);
    let body = StreamBody::new(stream);

    let mut body = Box::pin(body);
    assert!(matches!(body.as_mut().poll_frame(&mut cx), Poll::Ready(Some(Ok(Frame::Data(_))))));
}
