### RT-006: Timeout Expiration

```rust
conformance_test! {
    id: "rt-006",
    name: "Timeout expiration",
    description: "Timeout wrapping a future that exceeds deadline",
    category: TestCategory::Runtime,
    tags: ["timeout", "expiration"],
    expected: "Returns Err(Elapsed) after deadline",
    test: |rt| {
        rt.block_on(async {
            let start = Instant::now();

            let result = rt.timeout(
                Duration::from_millis(50),
                async {
                    rt.sleep(Duration::from_secs(10)).await;
                    42
                }
            ).await;

            let elapsed = start.elapsed();
            checkpoint("timeout_elapsed", json!({
                "elapsed_ms": elapsed.as_millis(),
                "result": format!("{:?}", result)
            }));

            assert!(result.is_err(), "Slow future should timeout");
            assert!(
                elapsed < Duration::from_millis(200),
                "Should timeout quickly, not wait for inner future"
            );

            TestResult::passed()
        })
    }
}
```

### RT-007: Select/Race First Wins

```rust
conformance_test! {
    id: "rt-007",
    name: "Select first completer wins",
    description: "Racing two futures, faster one wins",
    category: TestCategory::Runtime,
    tags: ["select", "race"],
    expected: "Returns result of faster future",
    test: |rt| {
        rt.block_on(async {
            let fast = async {
                rt.sleep(Duration::from_millis(10)).await;
                "fast"
            };
            let slow = async {
                rt.sleep(Duration::from_secs(10)).await;
                "slow"
            };

            let start = Instant::now();
            let winner = select(fast, slow).await;
            let elapsed = start.elapsed();

            checkpoint("race_completed", json!({
                "winner": winner,
                "elapsed_ms": elapsed.as_millis()
            }));

            assert_eq!(winner, "fast", "Fast future should win");
            assert!(
                elapsed < Duration::from_millis(100),
                "Should complete quickly"
            );

            TestResult::passed()
        })
    }
}
```

